import React, { useState } from 'react';

const EditOrder = ({ order, handleUpdate, handleCancel, vendors, locations }) => {
  const [editedOrder, setEditedOrder] = useState({ ...order });

  console.log(editedOrder);
  console.log(locations);


  const handleInputChange = (event) => {
    const { name, value } = event.target;
    setEditedOrder((prevorder) => ({
      ...prevorder,
      [name]: value,
    }));
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    handleUpdate(editedOrder);
    resetForm();
  };

  const resetForm = () => {
    setEditedOrder({
      // Reset the fields as needed for the order
      // Example:
      name: '',
      description: '',
      prmatcost: '',
      prlabcost: '',
      sale: '',
      realmatcost: '',
      reallabcost: '',
      totalcost: '',
      // Add other fields here
    });
  };

  return (
    <div className="container">
      <h2 className="heading">Edit order</h2>
      <form className="form" onSubmit={handleSubmit}>
        <div className='form-row'>
          <div className='form-group'>
            <label>
              order Name:
              <input
                type="text"
                name="order_list_id"
                value={editedOrder.order_list_id}
                onChange={handleInputChange}
              />
            </label>
          </div>
          <div className='form-group'>
            <label>
              Location:
              <label>
              Location:
              <select name="location_id" value={editedOrder.location_id} onChange={handleInputChange} required>
                <option value="">Select a location</option>
                {locations.map((location) => (
                  <option key={location.id} value={location.id}>
                    {location.locationname}
                  </option>
                ))}
              </select>
            </label>
            </label>
          </div>
          <div className='form-group'>
            <label>
            Order Quantity:
              <input
                type="number"
                name="quantity"
                value={editedOrder.quantity}
                onChange={handleInputChange}
              />
            </label>
          </div>
          <div className='form-group'>
          <label>
              Vendor:
              <select name="vendor_id" value={editedOrder.vendor_id} onChange={handleInputChange} required>
                <option value="">Select a vendor</option>
                {vendors.map((vendor) => (
                  <option key={vendor.vendorid} value={vendor.vendorid}>
                    {vendor.name}
                  </option>
                ))}
              </select>
            </label>
          </div>
          <div className='form-group'>
            <label>
              Sale:
              <input
                type="number"
                name="sale"
                value={editedOrder.sale}
                onChange={handleInputChange}
              />
            </label>
          </div>
          <div className='form-group'>
            <label>
              Real Material Cost:
              <input
                type="number"
                name="realmatcost"
                value={editedOrder.realmatcost}
                onChange={handleInputChange}
              />
            </label>
          </div>
          <div className='form-group'>
            <label>
              Real Labor Cost:
              <input
                type="number"
                name="reallabcost"
                value={editedOrder.reallabcost}
                onChange={handleInputChange}
              />
            </label>
          </div>
          <div className='form-group'>
            <label>
              Totalcost:
              <input
                type="number"
                name="totalcost"
                value={editedOrder.totalcost}
                onChange={handleInputChange}
              />
            </label>
          </div>
          <button type="submit">Edit order</button>
          <button type="button" className="add_btn" onClick={handleCancel}>
            Cancel
          </button>
        </div>
      </form>

    </div>
  );
};

export default EditOrder;
